INSERT INTO `vocab_sense` (id, word_id, part_of_speech, chinese_def, def_audio_id, translations, synonyms, antonyms, related_forward, related_backward, sense_order, create_time, update_time) VALUES (6, 5, 'm.p.', '用在句子的最后，表示不同的语气。', NULL, '[{"lang": "en", "text": "used at the end of the sentences to show different tones"}]', NULL, NULL, NULL, NULL, 0, NOW(), NOW());
INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (11, 5, 6, 'Exclamatory Sentence+<key>啊</key>：加强语气', 0, NOW(), NOW());
