INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (12, 2, 2, 'Declarative Sentence+<key>啊</key>：表达说话者吃惊、赞叹或者生气的态度', 0, NOW(), NOW());
INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (12, 2, 2, 12, '你生什么气啊？我没怪你<key>啊</key>！', NULL, NULL, NULL, 0, NOW(), NOW());
