INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (57, 2, 2, 57, '他想去打篮球，但他长得太<key>矮</key>了。', NULL, NULL, NULL, 0, NOW(), NOW());
