INSERT INTO `vocab_word` (id, word, word_traditional, pinyin, audio_id, hsk_level, create_time, update_time) VALUES (16, '艾滋病', NULL, 'àizībìng', NULL, NULL, NOW(), NOW());
INSERT INTO `vocab_sense` (id, word_id, part_of_speech, chinese_def, def_audio_id, translations, synonyms, antonyms, related_forward, related_backward, sense_order, create_time, update_time) VALUES (20, 16, 'n.', '一种很严重的传染病，通过性、血液传播，妈妈也能传给肚子里的孩子，得这种病以后身体抵抗力变弱，死的可能性很高。', NULL, '[{"lang": "en", "text": "acquired immunodeficiency syndrome (AIDS)"}]', NULL, NULL, NULL, NULL, 0, NOW(), NOW());
INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (60, 16, 20, 'V（得/传染/感染/治疗/防治/预防/了解/关注/研究）+<key>艾滋病</key>', 0, NOW(), NOW());
INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (60, 16, 20, 60, '他感染<key>艾滋病</key>以后，就很少出去玩<SMALL>儿</SMALL>了。', NULL, NULL, NULL, 0, NOW(), NOW());
INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (61, 2, 2, '<key>艾滋病</key>（+的）+病毒/患者/感染者/知识/研究/宣传/防治/症状', 0, NOW(), NOW());
INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (61, 2, 2, 61, '<key>艾滋病</key>患者要及时关注自己的健康状况。', NULL, NULL, NULL, 0, NOW(), NOW());
INSERT INTO `vocab_word` (id, word, word_traditional, pinyin, audio_id, hsk_level, create_time, update_time) VALUES (17, '爱', NULL, 'ài', NULL, NULL, NOW(), NOW());
INSERT INTO `vocab_sense` (id, word_id, part_of_speech, chinese_def, def_audio_id, translations, synonyms, antonyms, related_forward, related_backward, sense_order, create_time, update_time) VALUES (21, 17, 'v.', '对人或者事物有特别深的感情，特指男人和女人互相喜欢的特殊感情 。', NULL, '[{"lang": "en", "text": "to love"}]', NULL, NULL, '爱不释手|爱财如命|爱巢|爱称|爱戴|爱抚|爱岗|爱国|爱河|爱将|爱怜|爱恋|爱侣|爱神|爱屋及乌|爱心', '博爱|宠爱|慈爱|错爱|大爱|恩爱|抚爱|父爱|割爱|关爱|厚爱|敬爱|可爱|怜爱|恋爱|母爱|溺爱|偏爱|亲爱|情爱|求爱|热爱|仁爱|三角恋爱|示爱|抬爱|谈情说爱|疼爱|喜爱|心爱|性爱|友爱|珍爱|至爱|挚爱|钟爱|自爱|最爱', 0, NOW(), NOW());
INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (62, 17, 21, 'Sub+<key>爱</key>+O（Sb/孩子/父母/女朋友/男朋友/祖国/人民）', 0, NOW(), NOW());
