INSERT INTO `vocab_sense` (id, word_id, part_of_speech, chinese_def, def_audio_id, translations, synonyms, antonyms, related_forward, related_backward, sense_order, create_time, update_time) VALUES (34, 29, 'chunk', '爱和恨的态度特别清楚，不会随便改变自己的原则和态度。', NULL, '[{"lang": "en", "text": "know what to love and what to hate; take a clear-cut position; have clear views"}]', NULL, NULL, NULL, NULL, 0, NOW(), NOW());
