INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (106, 30, 35, 106, '把孩子带出去玩<SMALL>儿</SMALL>一会<SMALL>儿</SMALL>吧，他在这<SMALL>儿</SMALL><key>碍</key>我的<key>事</key>。', NULL, NULL, NULL, 0, NOW(), NOW());
