INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (107, 2, 2, 107, '桌子放在这<SMALL>儿</SMALL>很<key>碍事</key>，快点<SMALL>儿</SMALL>搬走吧。', NULL, NULL, NULL, 0, NOW(), NOW());
