INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (113, 2, 2, 113, '他们俩<key>暧昧</key>的眼神让大家都觉得不对劲<SMALL>儿</SMALL>。', NULL, NULL, NULL, 0, NOW(), NOW());
INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (114, 2, 2, 'V（搞/玩）+<key>暧昧</key>', 0, NOW(), NOW());
