INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (120, 2, 10, 120, '不要乱<key>安</key>罪名，你们说话、做事都要有证据。', NULL, NULL, NULL, 0, NOW(), NOW());
