INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (122, 33, 38, 'Sub（国家/社会/生活/人心/情绪/心神）+（很/不+）<key>安定</key>', 0, NOW(), NOW());
