INSERT INTO `vocab_example` (id, word_id, sense_id, structure_id, sentence, audio_id, pinyin, translations, example_order, create_time, update_time) VALUES (123, 2, 2, 123, '<key>安定</key>的社会和人心是经济发展的保障。', NULL, NULL, NULL, 0, NOW(), NOW());
