INSERT INTO `vocab_structure` (id, word_id, sense_id, pattern, structure_order, create_time, update_time) VALUES (265, 64, 69, '<key>暗中</key>+V（打听/走访/保护/观察/监视/操纵/勾结/串通/行贿/较量/做手脚）', 0, NOW(), NOW());
